-- ===================================================================
-- EduLens — Raven IQ vizual (rasmli) savollar
-- Rasmlar SVG koʻrinishida (single-quoted atributlar) saqlanadi.
-- question_type = 'matrix', image_svg = savol rasmi,
-- options[].svg = variant rasmlari, to'g'ri javob alohida jadvalda.
-- ===================================================================

-- Rasmli savollar uchun ustun
ALTER TABLE public.questions ADD COLUMN IF NOT EXISTS image_svg text;

-- Eski raven savollarini tozalash
DELETE FROM public.questions WHERE test_id IN (SELECT id FROM public.tests WHERE test_type = 'raven');

WITH t AS (SELECT id FROM public.tests WHERE test_type = 'raven' LIMIT 1)
INSERT INTO public.questions (test_id, question_number, question_text_uz, question_type, image_svg, options, subscale)
SELECT t.id, v.n, $tx$Mantiqiy ketma-ketlikni davom ettiring: ? oʻrniga qaysi shakl keladi?$tx$, 'matrix', v.img, v.opt::jsonb, NULL
FROM t, (VALUES
  -- Q1: nuqtalar soni 1,2,3 -> 4
  (1,
   $img$<svg xmlns='http://www.w3.org/2000/svg' viewBox='0 0 322 86' width='322' height='86'><g transform='translate(0,8)'><rect x='1' y='1' width='68' height='68' rx='8' fill='#F8FAFC' stroke='#CBD5E1' stroke-width='2'/><circle cx='35' cy='35' r='9' fill='#2563EB'/></g><g transform='translate(84,8)'><rect x='1' y='1' width='68' height='68' rx='8' fill='#F8FAFC' stroke='#CBD5E1' stroke-width='2'/><circle cx='24' cy='35' r='9' fill='#2563EB'/><circle cx='46' cy='35' r='9' fill='#2563EB'/></g><g transform='translate(168,8)'><rect x='1' y='1' width='68' height='68' rx='8' fill='#F8FAFC' stroke='#CBD5E1' stroke-width='2'/><circle cx='19' cy='35' r='8' fill='#2563EB'/><circle cx='35' cy='35' r='8' fill='#2563EB'/><circle cx='51' cy='35' r='8' fill='#2563EB'/></g><g transform='translate(252,8)'><rect x='1' y='1' width='68' height='68' rx='8' fill='#F8FAFC' stroke='#CBD5E1' stroke-width='2'/><text x='35' y='48' text-anchor='middle' font-size='36' fill='#94A3B8' font-family='sans-serif'>?</text></g></svg>$img$,
   $o$[{"value":1,"svg":"<svg xmlns='http://www.w3.org/2000/svg' viewBox='0 0 70 70' width='70' height='70'><rect x='1' y='1' width='68' height='68' rx='8' fill='#FFFFFF' stroke='#CBD5E1' stroke-width='2'/><circle cx='24' cy='35' r='9' fill='#2563EB'/><circle cx='46' cy='35' r='9' fill='#2563EB'/></svg>"},{"value":2,"svg":"<svg xmlns='http://www.w3.org/2000/svg' viewBox='0 0 70 70' width='70' height='70'><rect x='1' y='1' width='68' height='68' rx='8' fill='#FFFFFF' stroke='#CBD5E1' stroke-width='2'/><circle cx='19' cy='35' r='8' fill='#2563EB'/><circle cx='35' cy='35' r='8' fill='#2563EB'/><circle cx='51' cy='35' r='8' fill='#2563EB'/></svg>"},{"value":3,"svg":"<svg xmlns='http://www.w3.org/2000/svg' viewBox='0 0 70 70' width='70' height='70'><rect x='1' y='1' width='68' height='68' rx='8' fill='#FFFFFF' stroke='#CBD5E1' stroke-width='2'/><circle cx='25' cy='25' r='8' fill='#2563EB'/><circle cx='45' cy='25' r='8' fill='#2563EB'/><circle cx='25' cy='45' r='8' fill='#2563EB'/><circle cx='45' cy='45' r='8' fill='#2563EB'/></svg>"},{"value":4,"svg":"<svg xmlns='http://www.w3.org/2000/svg' viewBox='0 0 70 70' width='70' height='70'><rect x='1' y='1' width='68' height='68' rx='8' fill='#FFFFFF' stroke='#CBD5E1' stroke-width='2'/><circle cx='25' cy='25' r='7' fill='#2563EB'/><circle cx='45' cy='25' r='7' fill='#2563EB'/><circle cx='35' cy='35' r='7' fill='#2563EB'/><circle cx='25' cy='45' r='7' fill='#2563EB'/><circle cx='45' cy='45' r='7' fill='#2563EB'/></svg>"}]$o$
