-- Raven javob kalitlari (to'g'ri variant qiymati)
WITH t AS (SELECT id FROM public.tests WHERE test_type = 'raven' LIMIT 1)
INSERT INTO public.question_answer_keys (question_id, correct_answer)
SELECT que.id, jsonb_build_object('v', k.correct)
FROM t
JOIN public.questions que ON que.test_id = t.id
JOIN (VALUES
  (1, 3),  -- 4 ta nuqta
  (2, 3),  -- chapga
  (3, 3),  -- oltiburchak
  (4, 2),  -- bo'sh doira
  (5, 3),  -- r=26
  (6, 2)   -- o'ngda
) AS k(num, correct) ON k.num = que.question_number;

-- Savollar sonini yangilash
UPDATE public.tests SET question_count = (SELECT COUNT(*) FROM public.questions WHERE test_id = tests.id)
WHERE test_type = 'raven';
